-- ============================================================================
-- 文件作用：PostgreSQL 数据库初始化脚本
-- 包含：创建策略表、产品表、话术库表、执行计划表，插入初始产品数据和策略数据，所有字段均有中文注释
-- 产品表依据通信行业真实分类设计：个人套餐、语音包、语音超套、流量包、流量超套、
-- 短彩信、数字化权益（含移动云盘、咪咕系列等）、家庭宽带、移动高清、装修机、
-- 智能组网、安防、其他硬件、集团业务
-- ============================================================================
-- ============================================================================
-- PostgreSQL 数据库初始化脚本
-- 作用：删除并重建策略表、产品表、话术库表、执行计划表
-- 所有字段均有中文注释
-- ============================================================================
-- 第一步：删除现有表（按外键依赖倒序删除）
-- ============================================================================

DROP TABLE IF EXISTS scripts CASCADE;
DROP TABLE IF EXISTS execution_plans CASCADE;
DROP TABLE IF EXISTS strategies CASCADE;
DROP TABLE IF EXISTS products CASCADE;

-- ============================================================================
-- 第二步：创建产品表（基础表，无外键依赖）
-- ============================================================================

CREATE TABLE products (
    id VARCHAR(50) PRIMARY KEY,                     -- 产品ID
    name VARCHAR(500),                              -- 产品名称
    category VARCHAR(200),                          -- 一级分类：个人套餐/语音包/流量包/数字化权益/家庭宽带/硬件/集团业务等
    sub_category VARCHAR(200),                      -- 二级分类：如咪咕视频、移动云盘、智能组网等
    price VARCHAR(50),                              -- 售价（元）
    original_price VARCHAR(50),                     -- 原价（元）
    discount_supported VARCHAR(10) DEFAULT 'TRUE',  -- 是否支持优惠
    description TEXT,                               -- 产品描述
    target_user_type VARCHAR(200),                  -- 目标用户类型：高流量/低流量/新用户/老用户/家庭/企业
    package_size VARCHAR(200),                      -- 套餐包大小（如：5GB、100分钟、200条）
    valid_period VARCHAR(200),                      -- 有效期（如：当月有效、7天、长期）
    applicable_scope VARCHAR(500),                  -- 适用范围（如：全国、省内、定向APP）
    is_active VARCHAR(10) DEFAULT 'TRUE',           -- 是否上架
    created_at TIMESTAMPTZ DEFAULT NOW()            -- 创建时间
);

-- ============================================================================
-- 第三步：创建策略表（依赖products表的product_ids字段）
-- ============================================================================

CREATE TABLE strategies (
    id VARCHAR(50) PRIMARY KEY,                     -- 策略ID
    name VARCHAR(500),                              -- 策略名称
    category VARCHAR(200),                          -- 策略类别：挽留/交叉销售/升级/激活
    description TEXT,                               -- 策略详细描述
    product_ids VARCHAR(500),                       -- 关联的产品ID列表，逗号分隔
    conditions TEXT,                                -- 适用条件（如 ARPU>100）
    channel_preference VARCHAR(200),                -- 推荐渠道（短信/APP推送/邮件等）
    discount_ratio VARCHAR(50),                     -- 优惠折扣比例（0~1）
    avg_conversion_rate VARCHAR(50) DEFAULT '0',    -- 历史平均转化率（0~1）
    avg_roi VARCHAR(50) DEFAULT '0',                -- 历史平均ROI（投资回报率）
    avg_click_rate VARCHAR(50) DEFAULT '0',         -- 历史平均点击率/接通率（0~1）
    sample_count VARCHAR(50) DEFAULT '0',           -- 样本数量（用于统计置信度）
    is_active VARCHAR(10) DEFAULT 'TRUE',           -- 是否启用
    created_at TIMESTAMPTZ DEFAULT NOW(),           -- 创建时间
    updated_at TIMESTAMPTZ                          -- 更新时间
);

-- ============================================================================
-- 第四步：创建执行计划表（依赖strategies表）
-- ============================================================================

CREATE TABLE execution_plans (
    id VARCHAR(50) PRIMARY KEY,                     -- 计划ID
    strategy_id VARCHAR(50),                        -- 关联策略ID
    audience_segment VARCHAR(500),                  -- 客群分群描述
    channel VARCHAR(200),                           -- 推荐渠道（APP/短信/外呼等）
    wave_count VARCHAR(50) DEFAULT '1',             -- 波次数量
    wave_interval_hours VARCHAR(50),                -- 波次间隔（小时）
    send_time_preference VARCHAR(200),              -- 时刻偏好（如：晚间、上午、个性化）
    actual_conversion_rate VARCHAR(50),             -- 实际转化率
    actual_roi VARCHAR(50),                         -- 实际ROI
    usage_count VARCHAR(50) DEFAULT '0',            -- 使用次数
    created_at TIMESTAMPTZ DEFAULT NOW()            -- 创建时间
);

-- ============================================================================
-- 第五步：创建话术库表（依赖products和strategies表）
-- ============================================================================

CREATE TABLE scripts (
    id VARCHAR(50) PRIMARY KEY,                     -- 话术ID
    content TEXT NOT NULL,                          -- 话术内容
    scenario VARCHAR(500),                          -- 适用场景（如流量超套挽留）
    product_id VARCHAR(50),                         -- 关联产品ID
    strategy_id VARCHAR(50),                        -- 关联策略ID
    user_segment VARCHAR(200),                      -- 适用用户分群
    channel VARCHAR(200),                           -- 推荐渠道
    compliance_status VARCHAR(50) DEFAULT 'approved', -- 合规状态
    usage_count VARCHAR(50) DEFAULT '0',            -- 使用次数
    avg_ctr VARCHAR(50) DEFAULT '0',                -- 历史平均点击率
    created_at TIMESTAMPTZ DEFAULT NOW(),           -- 创建时间
    updated_at TIMESTAMPTZ                          -- 更新时间
);

